10	    pub data: Bytes,
11	}
12	
13	impl UdtDataPacket {
14	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
15	        let header = UdtDataPacketHeader::deserialize(&raw[..UDT_DATA_HEADER_SIZE])?;
16	        let data = Bytes::copy_from_slice(&raw[UDT_DATA_HEADER_SIZE..]);
17	        Ok(Self { header, data })
18	    }
19	
20	    pub fn payload_len(&self) -> u32 {
21	        self.data.len() as u32
22	    }
23	
24	    pub fn serialize(&self) -> Vec<u8> {
25	        let mut buffer = Vec::with_capacity(1500);
26	        buffer.extend_from_slice(&self.header.serialize());
27	        buffer.extend_from_slice(&self.data);
28	        buffer
29	    }
30	}
31	
32	#[derive(Debug)]
33	pub(crate) struct UdtDataPacketHeader {
34	    // bit 0 = 0
35	    pub seq_number: SeqNumber,    // bits 1-31
36	    pub position: PacketPosition, // bits 32-33
37	    pub in_order: bool,           // bit 34
38	    pub msg_number: MsgNumber,    // bits 35-63
39	    pub timestamp: u32,           // bits 64-95
40	    pub dest_socket_id: u32,      // bits 96-127
41	}
42	
43	impl UdtDataPacketHeader {
44	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
45	        if raw.len() < 16 {
46	            return Err(Error::new(
47	                ErrorKind::InvalidData,
48	                "data packet header is too short",
49	            ));
50	        }
51	        let seq_number = u32::from_be_bytes(raw[0..4].try_into().unwrap()) & 0x7fffffff;
52	        let position: PacketPosition = ((raw[4] & 0b11000000) >> 6).try_into()?;
53	        let in_order = (raw[4] & 0b00100000) != 0;
54	        let msg_number = u32::from_be_bytes(raw[4..8].try_into().unwrap()) & 0x1fffffff;
55	        let timestamp = u32::from_be_bytes(raw[8..12].try_into().unwrap());
56	        let dest_socket_id = u32::from_be_bytes(raw[12..16].try_into().unwrap());
57	        Ok(Self {
58	            seq_number: seq_number.into(),
59	            position,
60	            in_order,
61	            msg_number: msg_number.into(),
